[data-moduix-theme='dense'] {
  color-scheme: light;
  --background: oklch(0.985 0.004 255);
  --foreground: oklch(0.185 0.014 255);
  --card: oklch(0.998 0.002 255);
  --card-foreground: oklch(0.185 0.014 255);
  --popover: oklch(0.998 0.002 255);
  --popover-foreground: oklch(0.185 0.014 255);
  --primary: oklch(0.48 0.16 255);
  --primary-foreground: oklch(0.99 0.002 255);
  --secondary: oklch(0.958 0.009 255);
  --secondary-foreground: oklch(0.24 0.02 255);
  --muted: oklch(0.952 0.008 255);
  --muted-foreground: oklch(0.47 0.02 255);
  --accent: oklch(0.925 0.02 255);
  --accent-foreground: oklch(0.22 0.025 255);
  --border: oklch(0.88 0.015 255);
  --input: oklch(0.84 0.018 255);
  --ring: oklch(0.56 0.14 255);
  --overlay: oklch(0.16 0.02 255 / 0.24);
  --overlay-foreground: oklch(0.16 0.02 255 / 0.08);
  --sidebar: oklch(0.972 0.007 255);
  --sidebar-foreground: oklch(0.185 0.014 255);
  --sidebar-primary: oklch(0.48 0.16 255);
  --sidebar-primary-foreground: oklch(0.99 0.002 255);
  --sidebar-accent: oklch(0.925 0.02 255);
  --sidebar-accent-foreground: oklch(0.22 0.025 255);
  --sidebar-border: oklch(0.88 0.015 255);
  --sidebar-ring: oklch(0.56 0.14 255);
  --radius: 0.45rem;
  --spacing-1: 3px;
  --spacing-2: 6px;
  --spacing-3: 10px;
  --spacing-4: 14px;
  --spacing-5: 18px;
  --spacing-6: 22px;
  --spacing-8: 28px;
  --spacing-10: 36px;
  --size-xs: 22px;
  --size-sm: 30px;
  --size-md: 34px;
  --size-lg: 38px;
  --size-xl: 44px;
  --shadow-sm: 0 1px 2px rgb(15 23 42 / 0.08);
  --shadow-md: 0 3px 8px rgb(15 23 42 / 0.1);
  --shadow-lg: 0 12px 24px rgb(15 23 42 / 0.12);

  .dark,
  &.dark {
    color-scheme: dark;
    --background: oklch(0.16 0.014 255);
    --foreground: oklch(0.97 0.003 255);
    --card: oklch(0.205 0.016 255);
    --card-foreground: oklch(0.97 0.003 255);
    --popover: oklch(0.205 0.016 255);
    --popover-foreground: oklch(0.97 0.003 255);
    --primary: oklch(0.76 0.13 255);
    --primary-foreground: oklch(0.17 0.018 255);
    --secondary: oklch(0.255 0.018 255);
    --secondary-foreground: oklch(0.97 0.003 255);
    --muted: oklch(0.25 0.016 255);
    --muted-foreground: oklch(0.71 0.018 255);
    --accent: oklch(0.31 0.03 255);
    --accent-foreground: oklch(0.97 0.003 255);
    --border: oklch(0.72 0.02 255 / 0.25);
    --input: oklch(0.76 0.02 255 / 0.32);
    --ring: oklch(0.7 0.12 255);
    --overlay: oklch(0.1 0.02 255 / 0.78);
    --overlay-foreground: oklch(0.97 0.003 255 / 0.09);
    --sidebar: oklch(0.19 0.016 255);
    --sidebar-foreground: oklch(0.97 0.003 255);
    --sidebar-primary: oklch(0.76 0.13 255);
    --sidebar-primary-foreground: oklch(0.17 0.018 255);
    --sidebar-accent: oklch(0.31 0.03 255);
    --sidebar-accent-foreground: oklch(0.97 0.003 255);
    --sidebar-border: oklch(0.72 0.02 255 / 0.25);
    --sidebar-ring: oklch(0.7 0.12 255);
  }
}
